using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability by querying the Wikipedia API.
/// In production, replace with Bing Search API or similar.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (research-demo)" }
        }
    };

    [Description("Searches the web for information on a given query and returns relevant results. Use this to find facts, definitions, and background information on any topic.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&format=json&srlimit=5&srprop=snippet|titlesnippet&utf8=1";

            var json = await _httpClient.GetStringAsync(url, cancellationToken);
            var doc = JsonDocument.Parse(json);
            var results = doc.RootElement.GetProperty("query").GetProperty("search");

            if (results.GetArrayLength() == 0)
            {
                return $"No results found for '{query}'.";
            }

            var output = new List<string> { $"Search results for: \"{query}\"\n" };

            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("title").GetString();
                var snippet = result.GetProperty("snippet").GetString();

                // Strip HTML tags from the snippet
                snippet = System.Text.RegularExpressions.Regex.Replace(snippet ?? "", "<.*?>", "");

                output.Add($"- **{title}**: {snippet}");
            }

            return string.Join("\n", output);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetches the full summary of a Wikipedia article by its exact title. Use this after searching to get detailed information on a specific topic.")]
    public async Task<string> GetArticleSummaryAsync(
        [Description("The exact Wikipedia article title to fetch")] string title,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(title);
            var url = $"https://en.wikipedia.org/api/rest_v1/page/summary/{encoded}";

            var json = await _httpClient.GetStringAsync(url, cancellationToken);
            var doc = JsonDocument.Parse(json);

            var articleTitle = doc.RootElement.GetProperty("title").GetString();
            var extract = doc.RootElement.GetProperty("extract").GetString();

            return $"# {articleTitle}\n\n{extract}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch article '{title}': {ex.Message}";
        }
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides an in-memory notepad for the agent to collect and organize research findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short label for the note, e.g. 'Definition' or 'Key Fact'")] string topic,
        [Description("The content of the note")] string content,
        [Description("The source URL or reference for this information")] string source)
    {
        _notes.Add(new Note(topic, content, source, DateTime.UtcNow));
        return $"Note saved: [{topic}] ({_notes.Count} total notes)";
    }

    [Description("Retrieves all saved research notes. Use this to review what has been collected so far before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var output = new List<string> { $"=== Research Notes ({_notes.Count} total) ===\n" };

        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            output.Add($"{i + 1}. [{note.Topic}] {note.Content}");
            output.Add($"   Source: {note.Source}\n");
        }

        return string.Join("\n", output);
    }

    [Description("Clears all saved notes. Use this to start fresh if the research direction changes.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        return $"Cleared {count} notes.";
    }

    private sealed record Note(string Topic, string Content, string Source, DateTime Timestamp);
}

