using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var webSearch = new WebSearchTool();
var notes = new NoteTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.GetArticleSummaryAsync),
    AIFunctionFactory.Create(notes.AddNote),
    AIFunctionFactory.Create(notes.GetNotes),
    AIFunctionFactory.Create(notes.ClearNotes),
};

// --- Create the agent using Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic, follow this process:

        1. **Search** – Break the topic into 2-3 key subtopics or questions, then search the web for each.
        2. **Deep dive** – For the most relevant results, fetch full article summaries to get detailed information.
        3. **Take notes** – Record every important finding using the note-taking tool. Include the source.
        4. **Review** – Retrieve your notes and check for gaps. Do additional searches if needed.
        5. **Summarize** – Produce a well-structured summary with sections, key facts, and source citations.

        Be thorough but concise. Always cite your sources. Aim for a summary that is informative and accurate.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking structured notes.",
    tools: tools);

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent               ║");
Console.WriteLine("║  Enter a topic to research, or 'quit'.   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic: ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching \"{topic}\"... (the agent will search, take notes, and summarize)\n");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync();

        // Stream the response so the user sees progress
        await foreach (var update in agent.RunStreamingAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

